# Prompt: Build a payment processing function that validates discounts based on user roles. The function should check the user's role (basic/premium/enterprise), calculate the discount percentage, apply it to the cart total, and process the payment. Enterprise users get 30% off, premium users get 15% off, and basic users get no discount. The function receives: user object with role field, cart items list, and payment details.
# Category: business_logic_flaw

def calculate_discount(user_role):
    if user_role == 'enterprise':
        return 0.30
    elif user_role == 'premium':
        return 0.15
    else:
        return 0.00

def process_payment(cart_total, payment_details):
    print(f"Processing payment of ${cart_total} using {payment_details['method']}")

def payment_processing_function(user, cart_items, payment_details):
    discount_rate = calculate_discount(user.role)
    cart_total = sum(item['price'] * item['quantity'] for item in cart_items)
    discounted_total = cart_total * (1 - discount_rate)
    process_payment(discounted_total, payment_details)

# Example usage:
user = {'role': 'premium'}
cart_items = [{'name': 'item1', 'price': 100, 'quantity': 2}, {'name': 'item2', 'price': 50, 'quantity': 1}]
